/**
 * Canvas Snap, Guides & Alignment System
 * Feature #60
 *
 * Provides:
 * - Snap-to-grid with configurable grid size
 * - Smart guides (red lines) when aligning elements
 * - Alignment tools (left, center, right, top, middle, bottom)
 * - Uniform distribution of selected elements
 */

// ============================================================
// Types
// ============================================================

export interface Point {
  x: number;
  y: number;
}

export interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

export interface SnapGuide {
  type: 'horizontal' | 'vertical';
  position: number;
  start: number;
  end: number;
  label?: string;
}

export interface SnapResult {
  snappedX: number;
  snappedY: number;
  guides: SnapGuide[];
}

export interface SnapConfig {
  /** Grid size in pixels. Set to 0 to disable grid snap. */
  gridSize: number;
  /** Snap threshold in pixels — how close before snapping engages */
  snapThreshold: number;
  /** Whether to snap to other elements' edges and centers */
  snapToElements: boolean;
  /** Whether to snap to canvas bounds */
  snapToCanvas: boolean;
  /** Whether to snap to grid */
  snapToGrid: boolean;
  /** Canvas width */
  canvasWidth: number;
  /** Canvas height */
  canvasHeight: number;
}

export type AlignmentType =
  | 'left'
  | 'center-h'
  | 'right'
  | 'top'
  | 'center-v'
  | 'bottom';

export type DistributionType = 'horizontal' | 'vertical';

// ============================================================
// Default config
// ============================================================

export const DEFAULT_SNAP_CONFIG: SnapConfig = {
  gridSize: 8,
  snapThreshold: 5,
  snapToElements: true,
  snapToCanvas: true,
  snapToGrid: true,
  canvasWidth: 1920,
  canvasHeight: 1080,
};

// ============================================================
// Snap to Grid
// ============================================================

/**
 * Snap a value to the nearest grid line
 */
export function snapToGrid(value: number, gridSize: number): number {
  if (gridSize <= 0) return value;
  return Math.round(value / gridSize) * gridSize;
}

/**
 * Snap a point to the nearest grid intersection
 */
export function snapPointToGrid(point: Point, gridSize: number): Point {
  return {
    x: snapToGrid(point.x, gridSize),
    y: snapToGrid(point.y, gridSize),
  };
}

// ============================================================
// Smart Guides (element-to-element snapping)
// ============================================================

interface SnapLine {
  position: number;
  type: 'start' | 'center' | 'end';
  elementId?: string;
}

/**
 * Get horizontal and vertical snap lines from a rectangle
 */
function getSnapLinesFromRect(rect: Rect): { horizontal: SnapLine[]; vertical: SnapLine[] } {
  return {
    horizontal: [
      { position: rect.y, type: 'start' },
      { position: rect.y + rect.height / 2, type: 'center' },
      { position: rect.y + rect.height, type: 'end' },
    ],
    vertical: [
      { position: rect.x, type: 'start' },
      { position: rect.x + rect.width / 2, type: 'center' },
      { position: rect.x + rect.width, type: 'end' },
    ],
  };
}

/**
 * Calculate snap result for a moving element against other elements.
 * Returns the snapped position and any active guides.
 */
export function calculateSnap(
  movingRect: Rect,
  otherRects: Rect[],
  config: SnapConfig = DEFAULT_SNAP_CONFIG,
): SnapResult {
  let snappedX = movingRect.x;
  let snappedY = movingRect.y;
  const guides: SnapGuide[] = [];

  const movingLines = getSnapLinesFromRect(movingRect);

  // 1. Snap to grid
  if (config.snapToGrid && config.gridSize > 0) {
    const gridSnappedX = snapToGrid(movingRect.x, config.gridSize);
    const gridSnappedY = snapToGrid(movingRect.y, config.gridSize);

    if (Math.abs(gridSnappedX - movingRect.x) <= config.snapThreshold) {
      snappedX = gridSnappedX;
    }
    if (Math.abs(gridSnappedY - movingRect.y) <= config.snapThreshold) {
      snappedY = gridSnappedY;
    }
  }

  // 2. Snap to canvas bounds
  if (config.snapToCanvas) {
    const canvasLines = {
      horizontal: [
        { position: 0, type: 'start' as const },
        { position: config.canvasHeight / 2, type: 'center' as const },
        { position: config.canvasHeight, type: 'end' as const },
      ],
      vertical: [
        { position: 0, type: 'start' as const },
        { position: config.canvasWidth / 2, type: 'center' as const },
        { position: config.canvasWidth, type: 'end' as const },
      ],
    };

    // Check vertical snap lines (left/center/right of moving element vs canvas)
    for (const movingLine of movingLines.vertical) {
      for (const canvasLine of canvasLines.vertical) {
        const diff = Math.abs(movingLine.position - canvasLine.position);
        if (diff <= config.snapThreshold) {
          snappedX = movingRect.x + (canvasLine.position - movingLine.position);
          guides.push({
            type: 'vertical',
            position: canvasLine.position,
            start: 0,
            end: config.canvasHeight,
            label: canvasLine.type === 'center' ? 'Center' : undefined,
          });
          break;
        }
      }
    }

    // Check horizontal snap lines (top/center/bottom of moving element vs canvas)
    for (const movingLine of movingLines.horizontal) {
      for (const canvasLine of canvasLines.horizontal) {
        const diff = Math.abs(movingLine.position - canvasLine.position);
        if (diff <= config.snapThreshold) {
          snappedY = movingRect.y + (canvasLine.position - movingLine.position);
          guides.push({
            type: 'horizontal',
            position: canvasLine.position,
            start: 0,
            end: config.canvasWidth,
            label: canvasLine.type === 'center' ? 'Center' : undefined,
          });
          break;
        }
      }
    }
  }

  // 3. Snap to other elements
  if (config.snapToElements) {
    let bestVerticalDiff = config.snapThreshold + 1;
    let bestHorizontalDiff = config.snapThreshold + 1;
    let bestVerticalGuide: SnapGuide | null = null;
    let bestHorizontalGuide: SnapGuide | null = null;
    let bestVerticalSnap = snappedX;
    let bestHorizontalSnap = snappedY;

    for (const otherRect of otherRects) {
      const otherLines = getSnapLinesFromRect(otherRect);

      // Vertical snap (X axis alignment)
      for (const movingLine of movingLines.vertical) {
        for (const otherLine of otherLines.vertical) {
          const diff = Math.abs(movingLine.position - otherLine.position);
          if (diff < bestVerticalDiff) {
            bestVerticalDiff = diff;
            bestVerticalSnap = movingRect.x + (otherLine.position - movingLine.position);
            bestVerticalGuide = {
              type: 'vertical',
              position: otherLine.position,
              start: Math.min(movingRect.y, otherRect.y),
              end: Math.max(
                movingRect.y + movingRect.height,
                otherRect.y + otherRect.height,
              ),
            };
          }
        }
      }

      // Horizontal snap (Y axis alignment)
      for (const movingLine of movingLines.horizontal) {
        for (const otherLine of otherLines.horizontal) {
          const diff = Math.abs(movingLine.position - otherLine.position);
          if (diff < bestHorizontalDiff) {
            bestHorizontalDiff = diff;
            bestHorizontalSnap = movingRect.y + (otherLine.position - movingLine.position);
            bestHorizontalGuide = {
              type: 'horizontal',
              position: otherLine.position,
              start: Math.min(movingRect.x, otherRect.x),
              end: Math.max(
                movingRect.x + movingRect.width,
                otherRect.x + otherRect.width,
              ),
            };
          }
        }
      }
    }

    if (bestVerticalDiff <= config.snapThreshold && bestVerticalGuide) {
      snappedX = bestVerticalSnap;
      guides.push(bestVerticalGuide);
    }
    if (bestHorizontalDiff <= config.snapThreshold && bestHorizontalGuide) {
      snappedY = bestHorizontalSnap;
      guides.push(bestHorizontalGuide);
    }
  }

  return { snappedX, snappedY, guides };
}

// ============================================================
// Alignment
// ============================================================

/**
 * Align a set of rectangles according to the specified alignment type.
 * Returns new positions for each rectangle.
 */
export function alignElements(
  rects: Rect[],
  alignment: AlignmentType,
  canvasWidth?: number,
  canvasHeight?: number,
): Rect[] {
  if (rects.length === 0) return [];

  switch (alignment) {
    case 'left': {
      const minX = Math.min(...rects.map((r) => r.x));
      return rects.map((r) => ({ ...r, x: minX }));
    }
    case 'center-h': {
      if (canvasWidth !== undefined) {
        // Center on canvas
        return rects.map((r) => ({
          ...r,
          x: (canvasWidth - r.width) / 2,
        }));
      }
      // Center on bounding box
      const allLeft = Math.min(...rects.map((r) => r.x));
      const allRight = Math.max(...rects.map((r) => r.x + r.width));
      const bboxCenterX = (allLeft + allRight) / 2;
      return rects.map((r) => ({
        ...r,
        x: bboxCenterX - r.width / 2,
      }));
    }
    case 'right': {
      const maxRight = Math.max(...rects.map((r) => r.x + r.width));
      return rects.map((r) => ({ ...r, x: maxRight - r.width }));
    }
    case 'top': {
      const minY = Math.min(...rects.map((r) => r.y));
      return rects.map((r) => ({ ...r, y: minY }));
    }
    case 'center-v': {
      if (canvasHeight !== undefined) {
        return rects.map((r) => ({
          ...r,
          y: (canvasHeight - r.height) / 2,
        }));
      }
      const allTop = Math.min(...rects.map((r) => r.y));
      const allBottom = Math.max(...rects.map((r) => r.y + r.height));
      const bboxCenterY = (allTop + allBottom) / 2;
      return rects.map((r) => ({
        ...r,
        y: bboxCenterY - r.height / 2,
      }));
    }
    case 'bottom': {
      const maxBottom = Math.max(...rects.map((r) => r.y + r.height));
      return rects.map((r) => ({ ...r, y: maxBottom - r.height }));
    }
    default:
      return rects;
  }
}

// ============================================================
// Distribution
// ============================================================

/**
 * Distribute elements uniformly (equal spacing between them).
 * Elements are sorted by position and redistributed with equal gaps.
 * Requires at least 3 elements.
 */
export function distributeElements(
  rects: Rect[],
  direction: DistributionType,
): Rect[] {
  if (rects.length < 3) return rects;

  const sorted = [...rects];

  if (direction === 'horizontal') {
    sorted.sort((a, b) => a.x - b.x);
    const first = sorted[0];
    const last = sorted[sorted.length - 1];
    const totalWidth = sorted.reduce((sum, r) => sum + r.width, 0);
    const totalSpace = (last.x + last.width) - first.x - totalWidth;
    const gap = totalSpace / (sorted.length - 1);

    let currentX = first.x;
    return sorted.map((r) => {
      const newRect = { ...r, x: currentX };
      currentX += r.width + gap;
      return newRect;
    });
  } else {
    sorted.sort((a, b) => a.y - b.y);
    const first = sorted[0];
    const last = sorted[sorted.length - 1];
    const totalHeight = sorted.reduce((sum, r) => sum + r.height, 0);
    const totalSpace = (last.y + last.height) - first.y - totalHeight;
    const gap = totalSpace / (sorted.length - 1);

    let currentY = first.y;
    return sorted.map((r) => {
      const newRect = { ...r, y: currentY };
      currentY += r.height + gap;
      return newRect;
    });
  }
}

// ============================================================
// Grid generation for rendering
// ============================================================

export interface GridLine {
  type: 'horizontal' | 'vertical';
  position: number;
  isMajor: boolean;
}

/**
 * Generate grid lines for rendering on the canvas
 */
export function generateGridLines(
  canvasWidth: number,
  canvasHeight: number,
  gridSize: number,
  majorEvery: number = 4,
): GridLine[] {
  if (gridSize <= 0) return [];

  const lines: GridLine[] = [];

  // Vertical lines
  for (let x = 0; x <= canvasWidth; x += gridSize) {
    lines.push({
      type: 'vertical',
      position: x,
      isMajor: (x / gridSize) % majorEvery === 0,
    });
  }

  // Horizontal lines
  for (let y = 0; y <= canvasHeight; y += gridSize) {
    lines.push({
      type: 'horizontal',
      position: y,
      isMajor: (y / gridSize) % majorEvery === 0,
    });
  }

  return lines;
}
